```csharp
public abstract class SmartEnumeration<T> : ISmartEnumeration<T>
{
    protected SmartEnumeration(T value, string name, string description)
    {
        Value = value;
        Name = name;
        Description = description;
    }

    public T Value { get; }
    public string Name { get; }
    public string Description { get; }

    public virtual bool IsValid()
    {
        return true;
    }

    public virtual T GetNext()
    {
